VALUES
  ('retired-7ec62a85-moex-00023', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '依憲法訴訟法之規定，關於人民聲請憲法法庭判決，下列敘述何者錯誤？', '["人民聲請標的須包含法院確定裁判", "人民聲請須於確定終局裁判送達後6個月內為之", "人民聲請判決之案件如具有憲法重要性，憲法法庭得予受理", "人民聲請判決如程序要件不合，均直接由憲法法庭作成不受理裁定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00024', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '關於地方自治團體之法律主體保障，下列敘述何者錯誤？', '["我國憲法明文保障的地方自治團體包括縣（市）以及直轄市", "鄉（鎮、市）之地方自治團體地位不是憲法保障的法律主體", "某一直轄市或縣（市）被國家廢除或裁併，該直轄市或縣（市）可主張法律主體保障而要求不受廢 除與裁併", "國家若要廢除鄉（鎮、市）地方自治團體的地位，只須修法即可為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00025', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '依司法院大法官解釋及憲法法庭判決，下列敘述何者錯誤？', '["依行政執行法對酗酒泥醉者予以管束，無須經由法院為之", "依行政執行法所為管收，應經由法院為之", "依傳染病防治法所為強制隔離處置，無須經由法院為之", "依出入國移民法所為暫時收容之處分，應經由法院為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00026', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '有關戰後臺灣憲法發展史，下列敘述何者錯誤？', '["國民大會修正「動員戡亂時期臨時條款」，凍結了憲法第47條總統連任次數之限制", "司法院大法官做成的釋字第31號解釋，使得第一屆的國大代表、立法委員及監察委員得以不用定 期改選。直到解除戒嚴，政府再度辦理全國性之次屆中央民意代表選舉", "司法院大法官曾以司法院釋字第86號解釋要求高等以下之各級法院應改隸屬於司法院", "司法院大法官曾兩度宣告違警罰法部分規定不符憲法第8條第1項規定之本旨，然而立法院並未 修改該法規定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00027', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '國家的領域稱為領土，但解釋上此之領土尚包括領海、領空，此種解釋方法為：', '["體系解釋", "歷史解釋", "論理解釋", "類推適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00028', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '不具公務員身分的甲與公務員乙謀議收賄，而由甲出面收受賄款。關於甲的刑事責任，依實務見解， 下列敘述何者正確？', '["甲欠缺公務員身分，因此只能論以收賄罪的幫助犯", "甲欠缺公務員身分，與公務員共同實行收賄罪，仍得論以收賄罪之共同正犯", "甲欠缺公務員身分，因此只能論以收賄罪的教唆犯", "甲欠缺公務員身分，代公務員間接實行收賄罪，仍得論以收賄罪之間接正犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00029', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '就我國刑法中有關「刑」的敘述，下列何者正確？', '["主刑只有四種，分別為死刑、無期徒刑、有期徒刑與罰金", "從刑只有兩種，分別為褫奪公權與沒收", "刑期自裁判確定之日起算。裁判雖經確定，其尚未受拘禁之日數，不算入刑期內", "褫奪公權之宣告，自裁判宣告時發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00030', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '關於股份有限公司董事會，下列敘述何者錯誤？', '["若章程未規定不設置董事會，則董事不得少於3人", "董事會之召集通知，經相對人同意時，得以電子方式為之", "依主管機關實務見解，董事會於任何情況下均不得決定董事之報酬", "董事會開會得以視訊會議方式為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00031', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '甲公司業務性質特殊，工作通常下午才開始，也經常有夜間工作需求，因此希望透過勞動基準法規 定，將兩週內之正常工時，分配到其他工作日，增加人力運用彈性。但雇主跟工會素有糾紛，因此雇 主擬召開勞資會議之方式通過。下列敘述何者正確？', '["雇主應獲得工會之同意，但雇主跟工會不睦，因此雇主可以通知工會其決定，表示工會如3天內未 附理由拒絕，視同同意", "雖然有工會之企業應由工會同意，但勞資會議之決議也具有代表性，兩者擇一獲得同意就可以", "企業內有工會時，應獲得工會之同意，不得以勞資會議決議取代之", "如果企業確實有彈性工時需求，可請求工會同意，工會不同意時，才可以改透過勞資會議同意之方 式進行變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00032', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3d2b73b6', 'sub-retired-7ec62a85-02', NULL, 'single_choice', '甲受僱於乙公司，遭受主管丙性騷擾，雇主知悉後，召開調查會，決議性騷擾不成立。甲不服，向地 方勞工主管機關提出申訴，並要求乙給予公假，讓甲到勞工局接受調查，下列敘述何者正確？', '["乙依法應給予甲公假，不得拒絕", "乙得視業務調配情形，有正當理由，得予拒絕", "乙並非行為人，甲不得要求公假", "乙所召集之會議，調查結果為性騷擾不成立，甲不得再行申訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "7372d76e343d", "answer_pdf_sha1": "1f7241b9e683", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL)
